// WriteTerminalInput is the resolver for the writeTerminalInput field.
// Creates the session on demand if it doesn't exist yet.
func (r *mutationResolver) WriteTerminalInput(ctx context.Context, sessionID string, data string) (bool, error) {
	if r.TerminalMgr == nil {
		return false, fmt.Errorf("terminal support not available")
	}

	sess := r.TerminalMgr.Get(sessionID)
	if sess == nil {
		// Session doesn't exist yet — create it on demand so callers
		// don't need to race against the terminal pane's WebSocket init.
		var workDir string
		if sessionID == CentralSessionID {
			workDir = r.ProjectRoot
		} else if r.WorktreeMgr != nil {
			workDir = r.WorktreeMgr.WorktreePath(sessionID)
		}
		if workDir == "" {
			return false, fmt.Errorf("terminal session %q not found and cannot resolve work dir", sessionID)
		}
		var err error
		sess, _, err = r.TerminalMgr.GetOrCreate(sessionID, workDir, 80, 24)
		if err != nil {
			return false, fmt.Errorf("failed to create terminal session: %w", err)
		}
	}

	if _, err := sess.Write([]byte(data)); err != nil {
		return false, fmt.Errorf("write to terminal: %w", err)
	}

	return true, nil
}

// StartRun is the resolver for the startRun field.
func (r *mutationResolver) StartRun(ctx context.Context, workspaceID string) (int, error) {
	if r.TerminalMgr == nil {
		return 0, fmt.Errorf("terminal support not available")
	}

	cfg := r.Core.Config()
	if cfg == nil || cfg.GetWorktreeRun() == "" {
		return 0, fmt.Errorf("no run command configured")
	}

	var workDir string
	if workspaceID == CentralSessionID {
		workDir = r.ProjectRoot
	} else if r.WorktreeMgr != nil {
		workDir = r.WorktreeMgr.WorktreePath(workspaceID)
	}
	if workDir == "" {
		return 0, fmt.Errorf("cannot resolve work directory for workspace %q", workspaceID)
	}

	sessionID := workspaceID + RunSessionSuffix
	if _, err := r.TerminalMgr.CreateWithCommand(sessionID, workDir, 80, 24, cfg.GetWorktreeRun()); err != nil {
		return 0, fmt.Errorf("failed to start run session: %w", err)
	}

	port := 0
	if r.PortAlloc != nil {
		if p, err := r.PortAlloc.Get(workspaceID); err == nil {
			port = p
		}
	}

	return port, nil
}

// StopRun is the resolver for the stopRun field.
func (r *mutationResolver) StopRun(ctx context.Context, workspaceID string) (bool, error) {
	if r.TerminalMgr == nil {
		return false, fmt.Errorf("terminal support not available")
	}

	sessionID := workspaceID + RunSessionSuffix
	r.TerminalMgr.Close(sessionID)
	return true, nil
}

// CreateWorktree is the resolver for the createWorktree field.
func (r *mutationResolver) CreateWorktree(ctx context.Context, name string) (*model.Worktree, error) {
	if r.WorktreeMgr == nil {
		return nil, fmt.Errorf("worktree support not available")
	}

	wt, err := r.WorktreeMgr.Create(name)
	if err != nil {
		return nil, err
	}

	// Allocate a workspace port for this worktree
	if r.PortAlloc != nil {
		r.PortAlloc.Allocate(wt.ID)
	}

	// Start watching the worktree's .beans/ directory for bean changes
	if err := r.Core.WatchWorktreeBeans(wt.Path); err != nil {
		fmt.Printf("[beans] warning: failed to watch worktree beans: %v\n", err)
	}

	return worktreeToModel(wt, r.Core, r.WorktreeMgr.BaseRef(), false), nil
}

// RemoveWorktree is the resolver for the removeWorktree field.
func (r *mutationResolver) RemoveWorktree(ctx context.Context, id string) (bool, error) {
	if r.WorktreeMgr == nil {
		return false, fmt.Errorf("worktree support not available")
	}

	// Find the worktree path before removing (for unwatching)
	worktrees, _ := r.WorktreeMgr.List()
	for _, wt := range worktrees {
		if wt.ID == id {
			r.Core.UnwatchWorktreeBeans(wt.Path)
			break
		}
	}

	if err := r.WorktreeMgr.Remove(id); err != nil {
		return false, err
	}

	// Free the workspace port
	if r.PortAlloc != nil {
		r.PortAlloc.Free(id)
	}

	// Close any terminal session associated with this worktree
	if r.TerminalMgr != nil {
		r.TerminalMgr.Close(id)
	}

	return true, nil
}

// SendAgentMessage is the resolver for the sendAgentMessage field.
func (r *mutationResolver) SendAgentMessage(ctx context.Context, beanID string, message string, images []*model.ImageInput) (bool, error) {
	if r.AgentMgr == nil {
		return false, fmt.Errorf("agent manager not available")
	}

	var workDir string
	if beanID == CentralSessionID {
		// Central agent chat runs in the project root
		workDir = r.ProjectRoot
	} else {
		// Find the worktree path for this bean
		var err error
		workDir, err = r.findWorktreePath(beanID)
		if err != nil {
			return false, err
		}
	}

	var uploads []agent.ImageUpload
	for _, img := range images {
		data, err := base64.StdEncoding.DecodeString(img.Data)
		if err != nil {
			return false, fmt.Errorf("invalid base64 image data: %w", err)
		}
		uploads = append(uploads, agent.ImageUpload{Data: data, MediaType: img.MediaType})
	}

	if err := r.AgentMgr.SendMessage(beanID, workDir, message, uploads); err != nil {
		return false, err
	}
	return true, nil
}

