// BeanChanged is the resolver for the beanChanged field.
func (r *subscriptionResolver) BeanChanged(ctx context.Context, includeInitial *bool) (<-chan *model.BeanChangeEvent, error) {
	// Subscribe to bean events from beancore
	eventCh, unsubscribe := r.Core.Subscribe()

	// Create buffered output channel for GraphQL to reduce backpressure on the
	// subscriber channel. Without buffering, the resolver blocks on sends to gqlgen's
	// WebSocket transport, which prevents draining eventCh and causes fanOut to drop events.
	out := make(chan *model.BeanChangeEvent, 64)

	// Start goroutine to forward events
	go func() {
		defer unsubscribe()
		defer close(out)

		// If includeInitial is true, emit all current beans as a single snapshot
		if includeInitial != nil && *includeInitial {
			beans := r.Core.All()
			cfg := r.Core.Config()
			bean.SortByStatusPriorityAndType(beans, cfg.StatusNames(), cfg.PriorityNames(), cfg.TypeNames())

			select {
			case out <- &model.BeanChangeEvent{
				Type:  model.ChangeTypeInitialSnapshot,
				Beans: beans,
			}:
				// Sent successfully
			case <-ctx.Done():
				return
			}
		}

		for {
			select {
			case <-ctx.Done():
				// Client disconnected
				return
			case events, ok := <-eventCh:
				if !ok {
					// Channel closed (watcher stopped)
					return
				}

				// Forward each event to the GraphQL subscription
				for _, event := range events {
					gqlEvent := &model.BeanChangeEvent{
						BeanID: event.BeanID,
						Bean:   event.Bean,
					}

					// Convert event type
					switch event.Type {
					case beancore.EventCreated:
						gqlEvent.Type = model.ChangeTypeCreated
					case beancore.EventUpdated:
						gqlEvent.Type = model.ChangeTypeUpdated
					case beancore.EventDeleted:
						gqlEvent.Type = model.ChangeTypeDeleted
					}

					select {
					case out <- gqlEvent:
						// Sent successfully
					case <-ctx.Done():
						return
					}
				}
			}
		}
	}()

	return out, nil
}

// WorktreesChanged is the resolver for the worktreesChanged field.
func (r *subscriptionResolver) WorktreesChanged(ctx context.Context) (<-chan []*model.Worktree, error) {
	if r.WorktreeMgr == nil {
		out := make(chan []*model.Worktree)
		close(out)
		return out, nil
	}

	ch := r.WorktreeMgr.Subscribe()
	out := make(chan []*model.Worktree)

	// buildWorktreeList converts worktree structs to GraphQL models without PR data.
	buildWorktreeList := func(wts []worktree.Worktree) []*model.Worktree {
		result := make([]*model.Worktree, len(wts))
		for i, wt := range wts {
			result[i] = worktreeToModel(&wt, r.Core, r.WorktreeMgr.BaseRef(), false)
		}
		return result
	}

	// wg tracks in-flight populatePRsAsync goroutines so we can wait for them
	// to finish before closing the out channel, preventing send-on-closed-channel panics.
	var wg sync.WaitGroup

	// populatePRsAsync fetches PR data for all worktrees in a single batch query,
	// then re-emits the updated list on the output channel.
	populatePRsAsync := func(result []*model.Worktree) {
		defer wg.Done()
		if r.Forge == nil || len(result) == 0 {
			return
		}
		populatePRsBatch(ctx, result, r.Forge, r.ProjectRoot)
		select {
		case out <- result:
		case <-ctx.Done():
		}
	}

	go func() {
		defer r.WorktreeMgr.Unsubscribe(ch)
		defer close(out)
		defer wg.Wait()

		// Emit the current list immediately without PR data, then
		// fetch PR data in the background and re-emit.
		if wts, err := r.WorktreeMgr.List(); err == nil {
			result := buildWorktreeList(wts)
			select {
			case out <- result:
			case <-ctx.Done():
				return
			}
			wg.Add(1)
			go populatePRsAsync(result)
		}

		// Periodically re-fetch PR data so sidebar icons stay current
		// even when no worktree filesystem events occur.
		prTicker := time.NewTicker(30 * time.Second)
		defer prTicker.Stop()

		// refreshPRs fetches the current worktree list with PR data and emits it.
		refreshPRs := func() {
			wts, err := r.WorktreeMgr.List()
			if err != nil {
				return
			}
			result := buildWorktreeList(wts)
			wg.Add(1)
			go populatePRsAsync(result)
		}

		for {
			select {
			case <-ctx.Done():
				return
			case _, ok := <-ch:
				if !ok {
					return
				}
				wts, err := r.WorktreeMgr.List()
				if err != nil {
					continue
				}
				result := buildWorktreeList(wts)
				select {
				case out <- result:
				case <-ctx.Done():
					return
				}
				wg.Add(1)
				go populatePRsAsync(result)
			case <-prTicker.C:
				refreshPRs()
			}
		}
	}()

	return out, nil
}

// AgentSessionChanged is the resolver for the agentSessionChanged field.
func (r *subscriptionResolver) AgentSessionChanged(ctx context.Context, beanID string) (<-chan *model.AgentSession, error) {
	if r.AgentMgr == nil {
		out := make(chan *model.AgentSession)
		close(out)
		return out, nil
	}

	ch := r.AgentMgr.Subscribe(beanID)
	out := make(chan *model.AgentSession)

	go func() {
		defer r.AgentMgr.Unsubscribe(beanID, ch)
		defer close(out)

		// Emit current state immediately (if session exists)
		if s := r.AgentMgr.GetSession(beanID); s != nil {
			select {
			case out <- agentSessionToModel(s):
			case <-ctx.Done():
				return
			}
		}

		// Then emit on each change
		for {
			select {
			case <-ctx.Done():
				return
			case _, ok := <-ch:
				if !ok {
					return
				}
				s := r.AgentMgr.GetSession(beanID)
				var ms *model.AgentSession
				if s != nil {
					ms = agentSessionToModel(s)
				} else {
					// Session was cleared — send an empty session so the UI resets
					ms = &model.AgentSession{
						BeanID:    beanID,
						AgentType: "claude",
						Status:    model.AgentSessionStatusIdle,
						Messages:  []*model.AgentMessage{},
					}
				}
				select {
				case out <- ms:
				case <-ctx.Done():
					return
				}
			}
		}
	}()

	return out, nil
}

// ActiveAgentStatuses is the resolver for the activeAgentStatuses field.
func (r *subscriptionResolver) ActiveAgentStatuses(ctx context.Context) (<-chan []*model.ActiveAgentStatus, error) {
	if r.AgentMgr == nil {
		out := make(chan []*model.ActiveAgentStatus)
		close(out)
		return out, nil
	}

	ch := r.AgentMgr.SubscribeGlobal()
	out := make(chan []*model.ActiveAgentStatus)

	go func() {
		defer r.AgentMgr.UnsubscribeGlobal(ch)
		defer close(out)

		// Emit current state immediately
		select {
		case out <- activeAgentsToModel(r.AgentMgr.ListRunningSessions()):
		case <-ctx.Done():
			return
		}

		// Then emit on each change
		for {
			select {
			case <-ctx.Done():
				return
			case _, ok := <-ch:
				if !ok {
					return
				}
				select {
				case out <- activeAgentsToModel(r.AgentMgr.ListRunningSessions()):
				case <-ctx.Done():
					return
				}
			}
		}
	}()

	return out, nil
}

// WorkspaceStatuses is the resolver for the workspaceStatuses field.
func (r *subscriptionResolver) WorkspaceStatuses(ctx context.Context) (<-chan []*model.WorkspaceStatus, error) {
	out := make(chan []*model.WorkspaceStatus)

	go func() {
		defer close(out)

		var wtCh chan struct{}
		if r.WorktreeMgr != nil {
			wtCh = r.WorktreeMgr.Subscribe()
			defer r.WorktreeMgr.Unsubscribe(wtCh)
		}

		ticker := time.NewTicker(10 * time.Second)
		defer ticker.Stop()

		// Track last emitted state to avoid sending duplicates.
		type statusKey struct{ hasChanges, hasUnmergedCommits bool }
		var lastStatuses map[string]statusKey

		compute := func() []*model.WorkspaceStatus {
			var result []*model.WorkspaceStatus

			// Main workspace status
			result = append(result, &model.WorkspaceStatus{
				ID:         CentralSessionID,
				HasChanges: gitutil.HasChanges(r.ProjectRoot),
			})

			// Worktree statuses
			if r.WorktreeMgr != nil {
				baseRef := r.WorktreeMgr.BaseRef()
				if wts, err := r.WorktreeMgr.List(); err == nil {
					for _, wt := range wts {
						result = append(result, &model.WorkspaceStatus{
							ID:                 wt.ID,
							HasChanges:         gitutil.HasChanges(wt.Path),
							HasUnmergedCommits: gitutil.HasUnmergedCommits(wt.Path, baseRef),
						})
					}
				}
			}

			return result
		}

		changed := func(statuses []*model.WorkspaceStatus) bool {
			if len(statuses) != len(lastStatuses) {
				return true
			}
			for _, s := range statuses {
				prev, ok := lastStatuses[s.ID]
				if !ok || prev.hasChanges != s.HasChanges || prev.hasUnmergedCommits != s.HasUnmergedCommits {
					return true
				}
			}
			return false
		}

		emit := func() {
			statuses := compute()
			if !changed(statuses) {
				return
			}
			lastStatuses = make(map[string]statusKey, len(statuses))
			for _, s := range statuses {
				lastStatuses[s.ID] = statusKey{s.HasChanges, s.HasUnmergedCommits}
			}
			select {
			case out <- statuses:
			case <-ctx.Done():
			}
		}

		emit() // initial state

		for {
			select {
			case <-ctx.Done():
				return
			case <-ticker.C:
				emit()
			case _, ok := <-wtCh:
				if !ok {
					return
				}
				emit()
			}
		}
	}()

	return out, nil
}

// Bean returns BeanResolver implementation.
func (r *Resolver) Bean() BeanResolver { return &beanResolver{r} }

// Mutation returns MutationResolver implementation.
func (r *Resolver) Mutation() MutationResolver { return &mutationResolver{r} }

// Query returns QueryResolver implementation.
func (r *Resolver) Query() QueryResolver { return &queryResolver{r} }

// Subscription returns SubscriptionResolver implementation.
func (r *Resolver) Subscription() SubscriptionResolver { return &subscriptionResolver{r} }

type beanResolver struct{ *Resolver }
type mutationResolver struct{ *Resolver }
type queryResolver struct{ *Resolver }
type subscriptionResolver struct{ *Resolver }
